{
  "name": "gossamer-vscode",
  "displayName": "Gossamer",
  "description": "View Entire CLI session history and logs inside VS Code",
  "version": "0.1.0",
  "publisher": "gossamer",
  "engines": {
    "vscode": "^1.85.0"
  },
  "categories": ["Other"],
  "activationEvents": ["onStartupFinished"],
  "type": "module",
  "main": "./dist/extension.js",
  "contributes": {
    "commands": [
      {
        "command": "gossamer.openPanel",
        "title": "Gossamer: Open Session Viewer"
      },
      {
        "command": "gossamer.showCheckpointDiff",
        "title": "Gossamer: Show Checkpoint Diff"
      },
      {
        "command": "gossamer.searchSessions",
        "title": "Gossamer: Search Sessions"
      },
      {
        "command": "gossamer.copyCheckpointId",
        "title": "Copy Checkpoint ID"
      },
      {
        "command": "gossamer.copyCommitHash",
        "title": "Copy Commit Hash"
      },
      {
        "command": "gossamer.togglePanel",
        "title": "Gossamer: Toggle Panel"
      },
      {
        "command": "gossamer.restartServer",
        "title": "Gossamer: Restart Server"
      },
      {
        "command": "gossamer.focusSidebar",
        "title": "Gossamer: Focus Checkpoints Sidebar"
      },
      {
        "command": "gossamer.rewindToCheckpoint",
        "title": "Rewind to Checkpoint"
      }
    ],
    "menus": {
      "view/item/context": [
        {
          "command": "gossamer.rewindToCheckpoint",
          "when": "view == gossamer.checkpoints && viewItem == checkpoint",
          "group": "1_rewind@1"
        },
        {
          "command": "gossamer.copyCheckpointId",
          "when": "view == gossamer.checkpoints && viewItem == checkpoint",
          "group": "9_copy@1"
        },
        {
          "command": "gossamer.copyCommitHash",
          "when": "view == gossamer.checkpoints && viewItem == checkpoint",
          "group": "9_copy@2"
        }
      ]
    },
    "viewsContainers": {
      "activitybar": [
        {
          "id": "gossamer",
          "title": "Gossamer",
          "icon": "$(history)"
        }
      ]
    },
    "keybindings": [
      {
        "command": "gossamer.searchSessions",
        "key": "ctrl+shift+f",
        "mac": "cmd+shift+f",
        "when": "activeWebviewPanelId == 'gossamer'"
      },
      {
        "command": "gossamer.togglePanel",
        "key": "ctrl+k g",
        "mac": "ctrl+k g"
      },
      {
        "command": "gossamer.focusSidebar",
        "key": "ctrl+k ctrl+g",
        "mac": "ctrl+k ctrl+g"
      }
    ],
    "views": {
      "gossamer": [
        {
          "id": "gossamer.checkpoints",
          "name": "Checkpoints"
        }
      ]
    }
  },
  "scripts": {
    "build": "npm run build:extension && npm run build:webview",
    "build:extension": "tsc -p tsconfig.extension.json",
    "build:webview": "vite build",
    "dev:webview": "vite",
    "watch": "tsc -p tsconfig.extension.json --watch"
  },
  "dependencies": {
    "@gossamer/core": "*",
    "@mantine/core": "^7.0.0",
    "@mantine/hooks": "^7.0.0",
    "react": "^18.0.0",
    "react-dom": "^18.0.0"
  },
  "devDependencies": {
    "@types/node": "^22.0.0",
    "@types/react": "^18.0.0",
    "@types/react-dom": "^18.0.0",
    "@types/vscode": "^1.85.0",
    "@vitejs/plugin-react": "^4.0.0",
    "typescript": "^5.0.0",
    "vite": "^5.0.0"
  }
}

